import { Navbar, NavbarBrand, Nav, NavItem, Button, Container } from "reactstrap";
import { Link, useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { logout } from "../Features/UserSlice";

const Header = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector((state) => state.users.user);

  const handleLogout = () => {
    dispatch(logout());
    navigate("/login");
  };

  return (
    <Navbar expand="md" className="main-navbar py-3 shadow-sm mb-5" light>
      <Container>
        <NavbarBrand tag={Link} to="/" className="logo-text fw-bold" >Smart Daily Life </NavbarBrand>
        <Nav className="ms-auto" navbar>
          {user && user.email ? (
            <>
              <NavItem>
                <Link className="nav-link px-3" to="/">Home</Link>
              </NavItem>
              <NavItem>
                <Link  to="/addTask">Add Task</Link>
              </NavItem>
              <NavItem>
                <Button color="danger" outline size="sm" onClick={handleLogout} className="ms-3">
                  Logout
                </Button>
              </NavItem>
            </>
          ) : (
            <>
              <NavItem>
                <Link className="nav-link px-3" to="/login">Login</Link>
              </NavItem>
              <NavItem>
                <Link className="nav-link px-3" to="/register">Register</Link>
              </NavItem>
            </>
          )}
        </Nav>
      </Container>
    </Navbar>
  );
};

export default Header;
